def classify(score):
    if not (0.0 <= score <= 1.0):
        raise ValueError("score must be in [0, 1]")   # guard clause
    if score >= 0.9:
        return "high"
    elif score >= 0.5:
        return "medium"
    return "low"

print(classify(0.95))   # high
print(classify(0.3))    # low

